'use client';
import { useToast } from '@/hooks/use-toast';
import { getStatusStyle } from './buttonStatus';
import React, { useState, useEffect } from 'react';
import {
  MapPin,
  University,
  Rocket,
  Type,
  Calendar1,
  Building,
  Calendar,
  ShieldCheck,
  X,
  Download,
  Plus,
  Eye,
  Edit,
  Trash2,
  Gift,
  DollarSign,
} from 'lucide-react';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { motion, AnimatePresence } from 'framer-motion';
import EventCard from '@/components/ui/EventCard';
import { EventCategory } from '@/types';
import { useDebounce } from 'use-debounce';
import Link from 'next/link';
import { Calendar as CalendarComp } from '@/components/ui/calendar';
import { Button } from '@/components/ui/button';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { useAuth } from '@/context/AuthContext';
import Decorations from '@/components/ui/Decorations';
import DeleteConfirmationDialog from '@/components/dialog/DeleteConfirmationDialog';
import { StatCard } from '@/components/ui/StatCard';
import { stats } from '@/constants/stats';
import Pagination from '@/components/ui/Pagination';
import SearchInput from '@/components/ui/SearchInput';
import { Loading } from '@/components/ui/Loading';
import EventStatusDialog from '@/components/dialog/EventStatusDialog';
import { fetchEvents } from '@/api/events/events';
import { filterLabels } from '@/constants/filters';

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: {
    opacity: 1,
    y: 0,
    transition: {
      duration: 0.5,
      ease: 'easeOut',
    },
  },
  hover: {
    scale: 1.02,
    transition: {
      duration: 0.3,
    },
  },
};

const AllEventsPage = ({ className }: React.HTMLAttributes<HTMLDivElement>) => {
  const { toast } = useToast();
  const { token } = useAuth();
  const [events, setEvents] = useState<EventCategory[]>([]);
  const [date, setDate] = useState<Date | undefined>(new Date());
  const [activeFilter, setActiveFilter] = useState<
    'all' | 'upcoming' | 'past' | 'pending' | 'approved' | 'rejected'
  >('all');
  const [isPrice, setIsPrice] = useState(false);
  const [isFree, setIsFree] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 300);

  const [isCalendarOpen, setIsCalendarOpen] = useState(false);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);

  const [currentPage, setCurrentPage] = useState(1); // حالة Pagination الجديدة
  const [totalPages, setTotalPages] = useState(0);
  const [totalItems, setTotalItems] = useState(0);
  const [eventsPerPage] = useState(6); // عدد الأحداث في كل صفحة

  const [loading, setLoading] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<EventCategory | null>(
    null
  );

  const [isStatusDialogOpen, setIsStatusDialogOpen] = useState(false);
  const [statusAction, setStatusAction] = useState<'approve' | 'reject' | null>(
    null
  );

  const [downloadingReportpdf, setDownloadingReportpdf] = useState<
    string | null
  >(null);

  // Function to download invoice
  const downloadingReport = async (eventId: string) => {
    if (!token) return;

    setDownloadingReportpdf(eventId);
    try {
      const response = await fetch(
        `http://localhost:8080/reports/event/${eventId}`,
        {
          method: 'GET',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        }
      );

      if (!response.ok) {
        throw new Error(await response.text());
      }

      // Create blob from response
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);

      // Create download link
      const a = document.createElement('a');
      a.href = url;
      a.download = `Invoice-${eventId}.pdf`;
      document.body.appendChild(a);
      a.click();

      // Cleanup
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      toast({
        title: 'Invoice downloaded',
        description: 'The invoice has been successfully downloaded.',
        className: 'bg-green-500 text-white',
      });
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error?.message || 'Failed to download invoice',
        className: 'bg-red-600 text-white border-0',
      });
    } finally {
      setDownloadingReportpdf(null);
    }
  };

  useEffect(() => {
    fetchEvents({
      token,
      currentPage,
      eventsPerPage,
      activeFilter,
      role: 'admin',
      toast,
      setLoading,
    }).then((data) => {
      setEvents(data.events);
      setTotalPages(data.totalPages);
      setTotalItems(data.totalItems);
    });
  }, [currentPage, activeFilter]);

  const approvedCount = events.filter((e) => e.status === 'approved').length;
  const pendingCount = events.filter((e) => e.status === 'pending').length;
  const rejectedCount = events.filter((e) => e.status === 'rejected').length;

  // تصفية الأحداث
  const currentEvents = events?.filter((event) => {
    const matchesSearch = event?.title
      ?.toLowerCase()
      .includes(debouncedQuery.toLowerCase());

    const matchesBasicFilter =
      activeFilter === 'all' ||
      (activeFilter === 'upcoming' && event.status === 'upcoming') ||
      (activeFilter === 'past' && event.status === 'past') ||
      (activeFilter === 'pending' && event.status === 'pending') ||
      (activeFilter === 'approved' && event.status === 'approved') ||
      (activeFilter === 'rejected' && event.status === 'rejected');

    const matchesPriceFilter =
      (!isPrice && !isFree) ||
      (isPrice && event?.price !== 0) ||
      (isFree && event?.price === 0);

    return matchesSearch && matchesBasicFilter && matchesPriceFilter;
  });

  // تغيير الصفحة
  const paginate = (pageNumber: number) => setCurrentPage(pageNumber);

  const onDelete = (event: EventCategory) => {
    setSelectedEvent(event);
    setIsDeleteDialogOpen(true);
  };

  // 🟢 Delete Event
  const handleDelete = async () => {
    if (!selectedEvent) return;

    try {
      const res = await fetch(
        `http://localhost:8080/host/events/${selectedEvent._id}`,
        {
          method: 'DELETE',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        }
      );
      const data = await res.json();
      if (res.ok) {
        setEvents((prev) =>
          prev.filter((event) => event._id !== selectedEvent._id)
        );
        toast({
          title: 'Event Deleted',
          description: data.message,
          className: 'bg-green-600 text-white border-0',
        });
      } else {
        throw new Error(data.message || 'Failed to delete event');
      }
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error?.message || 'An unexpected error occurred.',
        className: 'bg-red-500 text-white border-0',
      });
    } finally {
      setIsDeleteDialogOpen(false);
      setSelectedEvent(null);
    }
  };
  const statsValue = {
    totalItems: totalItems,
  };

  // إعادة تعيين الصفحة إلى 1 عند تغيير الفلتر
  useEffect(() => {
    setCurrentPage(1);
  }, [activeFilter]);

  // إعادة تعيين فلاتر السعر عند تغيير الفلتر الأساسي
  useEffect(() => {
    setIsPrice(false);
    setIsFree(false);
  }, [activeFilter]);

  if (loading) {
    return <Loading />;
  }

  return (
    <main className='bg-white min-h-screen relative'>
      <div className='max-w-6xl mx-auto px-4 relative'>
        {/* Stats */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.4 }}
          className='grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6'
        >
          {stats.map((stat, index) => (
            <StatCard
              key={index}
              title={stat.title}
              value={statsValue.totalItems}
              change={stat.change}
              icon={stat.icon}
              delay={index * 0.1}
            />
          ))}
        </motion.div>
        {/* Controls */}
        <motion.div
          className='flex flex-col lg:flex-row gap-4 items-stretch my-8'
          variants={itemVariants}
        >
          {/* Search Input */}
          <SearchInput
            name='Events'
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            setCurrentPage={() => setCurrentPage(1)}
          />
          {/* Filters Tabs */}
          <div className='flex-1 overflow-x-auto'>
            <Tabs
              value={activeFilter}
              onValueChange={(val) => {
                setActiveFilter(val as typeof activeFilter);
                setCurrentPage(1);
              }}
              className='w-full'
            >
              <TabsList className='bg-transparent gap-1 p-1 flex-wrap justify-start w-full'>
                {filterLabels.map(({ label, icon: Icon, value }) => (
                  <TabsTrigger
                    value={value as typeof activeFilter}
                    key={value}
                    className='data-[state=active]:bg-purple-600 data-[state=active]:text-white rounded-full px-3 py-1 text-xs md:text-sm md:px-4 md:py-2 transition-all whitespace-nowrap'
                  >
                    <div className='flex items-center gap-1 md:gap-2'>
                      <Icon className='h-3 w-3 md:h-4 md:w-4' />
                      {label}
                    </div>
                  </TabsTrigger>
                ))}
              </TabsList>
            </Tabs>
          </div>

          {/* Price/Free toggles */}
          <div className='flex gap-2 items-center'>
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => {
                setIsFree(!isFree);
                if (!isFree) setIsPrice(false);
                setCurrentPage(1);
              }}
              className={`relative flex items-center gap-2 px-4 py-2 rounded-full border-2 transition-all duration-300
                ${isFree ? 'border-purple-500/30 bg-purple-600 text-white' : 'border-white/10 bg-purple-900 text-white'}`}
            >
              <Gift className='h-4 w-4' />
              <span className='text-sm'>Free</span>
            </motion.button>
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => {
                setIsPrice(!isPrice);
                if (!isPrice) setIsFree(false);
                setCurrentPage(1);
              }}
              className={`relative flex items-center gap-2 px-4 py-2 rounded-full border-2 transition-all duration-300
                ${isPrice ? 'border-purple-500/30 bg-purple-600 text-white' : 'border-white/10 bg-purple-900 text-white'}`}
            >
              <DollarSign className='h-4 w-4' />
              <span className='text-sm'>Price</span>
            </motion.button>
          </div>

          {/* Calendar Popover */}
          <Popover
            open={isCalendarOpen}
            onOpenChange={setIsCalendarOpen}
          >
            <PopoverTrigger asChild>
              <Button
                variant='outline'
                className='rounded-full gap-2'
              >
                <Calendar className='h-4 w-4' />
                <span>Select Date</span>
              </Button>
            </PopoverTrigger>
            <PopoverContent
              className='w-auto p-0'
              align='end'
            >
              <CalendarComp
                mode='single'
                selected={date}
                onSelect={(selectedDate) => {
                  setDate(selectedDate);
                  setIsCalendarOpen(false);
                }}
                initialFocus
              />
            </PopoverContent>
          </Popover>
          {/* Create Event */}
          <Button className='bg-gradient-to-r from-purple-800 to-pink-700'>
            <Plus className='text-white'></Plus>
            <Link href='/create'>Create Events</Link>
          </Button>
        </motion.div>

        {currentEvents?.length > 0 ? (
          <motion.div
            className='grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8'
            initial='hidden'
            animate='visible'
            variants={{
              hidden: { opacity: 0 },
              visible: {
                opacity: 1,
                transition: {
                  staggerChildren: 0.1,
                  delayChildren: 0.2,
                },
              },
            }}
          >
            <AnimatePresence>
              {currentEvents.map((event) => {
                const statusInfo = getStatusStyle(event.status);
                return (
                  <motion.div
                    key={event._id}
                    variants={{
                      hidden: { opacity: 0, y: 20 },
                      visible: { opacity: 1, y: 0 },
                    }}
                    whileHover={{
                      y: -5,
                      transition: { type: 'spring', stiffness: 300 },
                    }}
                    className='relative group'
                  >
                    <EventCard
                      event={event}
                      className='transition-all duration-300 group-hover:shadow-xl group-hover:shadow-purple-500/20 group-hover:border-cyan-400/30'
                      role='admin'
                      actionsMode='menu'
                      onApprove={() => {
                        setSelectedEvent(event);
                        setStatusAction('approve');
                        setIsStatusDialogOpen(true);
                      }}
                      onReject={() => {
                        setSelectedEvent(event);
                        setStatusAction('reject');
                        setIsStatusDialogOpen(true);
                      }}
                      onStatusChange={() => {
                        setSelectedEvent(event);
                        setStatusAction('approve');
                        setIsStatusDialogOpen(true);
                      }}
                      onEdit={() => {
                        window.location.href = `/admin/events/${event._id}/edit`;
                      }}
                      onDelete={() => onDelete(event)}
                      onDownloadInvoice={() => downloadingReport(event._id)}
                    />
                  </motion.div>
                );
              })}
            </AnimatePresence>
          </motion.div>
        ) : (
          <motion.div
            className='text-center py-30 space-y-4'
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
          >
            <div className='text-xl font-bold'>No events found</div>
            <p className='text-muted-foreground'>
              {searchQuery
                ? 'Try a different search term'
                : 'Create your first event to get started'}
            </p>
            {/* Create Event */}
            <Button className='bg-gradient-to-r from-purple-800 to-pink-700'>
              <Plus className='text-white'></Plus>
              <Link href='/create'>Create Events</Link>
            </Button>
          </motion.div>
        )}
      </div>

      {/* Pagination Controls */}
      {currentEvents.length > 0 && (
        <Pagination
          currentPage={currentPage}
          totalPages={totalPages}
          totalItems={totalItems}
          paginate={paginate}
        />
      )}
      {/* Decorations */}
      <Decorations />
      {/* Delete Confirmation Modal */}
      <DeleteConfirmationDialog
        open={isDeleteDialogOpen}
        onClose={() => setIsDeleteDialogOpen(false)}
        title='Delete Event'
        description={`Are you sure you want to delete ${selectedEvent?.title}?`}
        onConfirm={handleDelete}
      />
      <EventStatusDialog
        open={isStatusDialogOpen}
        onClose={() => setIsStatusDialogOpen(false)}
        event={selectedEvent}
        action={statusAction!}
        onSuccess={(updatedEvent) => {
          setEvents((prev) =>
            prev.map((e) => (e._id === updatedEvent._id ? updatedEvent : e))
          );
        }}
      />
    </main>
  );
};
export default AllEventsPage;